query:
SELECT id, version_label, effective_date, imported_at, is_active, source_filename 
FROM sasboss_pricebook_versions ORDER BY id;

SELECT sheet_name, COUNT(*) as item_count 
FROM sasboss_pricebook_items 
GROUP BY sheet_name;

SELECT product_name, partner_buy_price, partner_sell_price, partner_margin
FROM sasboss_pricebook_items 
WHERE product_name LIKE '%UCXcel Webex Basic%' OR product_name LIKE '%Webex Basic%';

